  ('aboriginal-f0899a01-moex-00557', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '有關司法院大法官，下列敘述何者錯誤？', '["目前大法官法定總額為15人", "目前所有大法官之任期，均為8年，其任期並受保障", "大法官由總統提名，經立法院同意後任命之", "大法官具有審理立法院彈劾總統、副總統案之權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
