  ('aboriginal-f0899a01-moex-00559', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '1997年透過修憲而將省虛級化（即所謂「凍省」），下列敘述何者錯誤？', '["不再舉行省長選舉", "不再舉行省議會選舉", "省主席與省府委員由行政院院長提請總統任命", "省仍為地方自治團體之公法人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00560', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '根據原住民族文化資產處理辦法，文化資產保存法第13條第2款中所稱「具原住民族文化特性及差 異性，但無法依第3條規定類別辦理者之保存事項」之審議，應優先以何種型式指定或登錄原住民族 文化資產？', '["系統性或複合型", "系統性或整合型", "多元型或複合型", "多元型或整合型"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00561', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依據財團法人原住民族文化事業基金會設置條例，下列何者非屬該基金會之業務範圍？', '["原住民族廣播、電視專屬頻道之規劃、製播、經營及普及服務", "原住民族文化及傳播出版品之發行及推廣", "原住民參政等活動之輔導、辦理及贊助", "原住民族文化、語言、藝術及傳播等工作者之培育及獎助"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00562', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依據聯合國原住民族權利宣言，下列敘述何者錯誤？', '["原住民族享有自決權。以國家安全為限，他們可自由決定自己的政治地位，自由謀求自身的經濟、 社會和文化發展", "原住民族和個人有權按照一個原住民族社區或民族的傳統和習俗，歸屬該社區或民族。此項權利的 行使不得引起任何形式的歧視", "各國應採取有效措施，並在適當情況下採取特別措施，確保原住民族的經濟和社會狀況持續得到改 善。應特別關注原住民族老人、婦女、青年、兒童和殘疾人的權利和特殊需要", "原住民族對他們傳統上擁有、佔有或以其他方式使用或獲得的土地、領土和資源擁有權利"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00563', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依據原住民族委員會組織法，原住民族委員會委員應有多少人數具原住民族身分？', '["三分之一以上", "二分之一以上", "三分之二以上", "全數"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00564', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依據原住民族傳統智慧創作保護條例，下列敘述何者正確？', '["本條例所稱主管機關為經濟部智慧財產局", "本條例所稱智慧創作，包括原住民族傳統之圖案", "智慧創作於創作完成時，受本條例之保護", "智慧創作登記申請人為該文化成果表達之原住民"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00565', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依據原住民族傳統智慧創作保護條例，關於智慧創作專用權之限制規定，下列敘述何者錯誤？', '["供個人或家庭為非營利之目的使用者", "為報導、評論、教育或研究之必要使用者", "為其他正當之目的，以合理方法使用者", "依法使用原住民族傳統智慧創作者，均無須註明出處"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00566', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依據原住民重點學校及原住民教育班教師主任校長聘任遴選辦法，下列敘述何者錯誤？', '["原住民重點學校及原住民教育班教師甄選時，參與甄選者須具原住民身分", "原住民重點學校及原住民教育班應於當年度教師缺額一定比率，聘任原住民各族教師", "原住民重點學校教師編制員額內，以至少聘任一位具備民族教育教師資格之教師為原則", "各該教育主管機關辦理公立中小學校長遴選時，其中原住民學生人數達全校學生人數二分之一之原 住民重點學校校長，應就經依法組成之校長遴選委員會審查通過之校長候選人中具原住民身分者， 優先聘任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
